#include<bits/stdc++.h>
using namespace std;
using pii=pair<int,int>;
const int maxn=2e5+5;
int n,m,k;
struct node {
	vector<int>e;
	int d=-1;
} v[maxn];
pii p[maxn];
int q[maxn],len;
void check(int x,int y){
	if(v[x].d==-1){
		v[x].d=y;
		q[++len]=x;
	}
}

int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m>>k;
	for(int i=1,x,y; i<=m; i++) {
		cin>>x>>y;
		v[x].e.emplace_back(y),v[y].e.emplace_back(x);
	}
	for(int i=1; i<=k; i++) {
		cin>>p[i].second>>p[i].first;
	}
	sort(p+1,p+1+n,greater<pii>());
	for(int i=1,j=1; i<=len||j<=k; ) {
		if(i>len || j<=k && p[j].first==v[q[i]].d) {
			check(p[j].second,p[j].first);
			j++;		
		}else{
			if(v[q[i]].d){
				for(int x:v[q[i]].e){
					check(x,v[q[i]].d-1);
				}
			}
			i++;
		} 
	}
	cout<<len<<endl;
	for(int i=1;i<=n;i++){
		if(v[i].d!=-1) cout<<i<<" ";
	}
	return 0;
}
